impl.spec_text:
trait T<A> { spec fn f(a: A) -> bool; }
struct S {}
impl T<u8> for S { spec fn f(a: u8) -> bool { true } }
impl T<u16> for S { spec fn f(a: u16) -> bool { false } }
proof fn test() {
    assert(S::f(1u8));
    assert(!S::f(1u16));
}

